class Solution {
    public boolean canFinish(int numCourses, int[][] prerequisites) {
        List<Integer>[] graph = new List[numCourses];
        for (int i = 0; i < numCourses; i++) {
            graph[i] = new ArrayList<>();
        }
        for (int[] p : prerequisites) {
            graph[p[0]].add(p[1]);
        }
        boolean[] visited = new boolean[numCourses];
        boolean[] onPath = new boolean[numCourses];
        for (int i = 0; i < numCourses; i++) {
            if (!dfs(graph, visited, onPath, i)) {
                return false;
            }
        }
        return true;
    }

    private boolean dfs(List<Integer>[] graph, boolean[] visited, boolean[] onPath, int node) {
        if (onPath[node]) {
            return false;
        }
        if (visited[node]) {
            return true;
        }
        onPath[node] = true;
        for (int neighbor : graph[node]) {
            if (!dfs(graph, visited, onPath, neighbor)) {
                return false;
            }
        }
        onPath[node] = false;
        visited[node] = true;
        return true;
    }
}
